window.__QUIZ_DATA__=[{"id":"theory>Agricultural Science Practical>2010>1>a>i","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"i","group":"","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes    Describe the procedure used in concting the experiment","images":[],"marking_scheme":"Description of the procedure used ln conducting the experiment    -Some quantity of soil was weighed  -The soil was put in a 250cm measuring cylinder  -Some water was added to the soil in the cylinder to submerge the soil  -A little quantity of sodium carbonate was added into the cylinder  -A hand was placed over the opening of the cylinder  -The cylinder was then placed on a flat level bench for at least an hour to allow contents settle","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>1>a>ii","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"ii","group":"","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State your observations and results","images":[],"marking_scheme":"Observations and results -      -The soil fractions settled in layers  -The bigger gravels settled first   -Followed by sand  -And silt and  -Clay  -Colloids remained in suspension  -Humus and organic materials were seen floating  -Depth of each layer was read from the marks on the cylinder.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>1>b","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State one function of each of specimens B and specimen C in the experiment","images":[],"marking_scheme":"Function of Specimen B (water) and Specimen C (sodium carbonate) in the experiment     Water (Specimen)     -Provides a medium for dispersing the soil and dissolve the chemical  -Enhances the differential settling of materials  Sodium Carbonate (Specimen C)    -Enhances complete dispersal of soil aggregates/faster  -Makes/renders the reading of the levels/layers easier","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>1>c","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Using specimens A, B (WATER), C (SODIUM CARBONATE).and D, carry out an experiment to show that soil is made up of different particle sizes  State three precautions taken in carrying out the experiment.","images":[],"marking_scheme":"Precautions to take in carrying out the experiment -    -Cover the opening of the cylinder well to prevent spillage when shaking  -Do not add too much sodium carbonate to the soil as that will reduce readability of layers  -Allow sufficient time for content to settle properly  -Place cylinder on a horizontal surface to ensure correct reading  -Avoid error of parallax when reading results  -Enough water should be added to the soil to allow free floatation and sedimentation, otherwise, the experiment will not work.","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>2>a","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"a","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"Describe briefly each of specimens G (CUTLASS), H (HOE), and l (SHORT HANDLE SICKLE)","images":[],"marking_scheme":"Specimen G (Cutlass)    -Has a long and flat metal blade  -One edge of the metal blade is sharp while the other edge is blunt  -Has a short wooden/rubber/metal handle at one end of the blade    Specimen H (Hoe)    -Has a long wooden/metal handle of variable length  -Has a metal blade which could be triangular or circular or rectangular in shape  -Metal blade is attached to one end of the handle b ns of a slim pointed metal projection     Specimen I (Short handle Sick\u00ede)    -Has a curved metal blade  -The edge which is curved inside is sharp while the other edge is blunt  -Has a short wooden handle attached to one end of the curved metal blade.","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2010>2>b","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"b","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"State two uses of each of specimens G, H, and I","images":[],"marking_scheme":"Uses of Specimens G, H, and I;    Specimen G (CUTLASS) -    -For weeding   -For pruning   -Use for clearing the bush/slashing/brushing  -For cutting woods  -For planting  -For harvesting  -For transplanting  -Digging holes    Specimen H (HOE):    -Used for making ridges or heaps/seedbeds/mounds  -For weeding  -Planting or sowing seeds  -For harvesting  -Digging holes  -For loosening/turning the soil    Specimen I (SHORT HANDLE SICKLE);    -Used for harvesting cereals such as rice  -Used for cutting forage grasses for livestock.  -For weeding","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2010>2>c","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"c","group":"","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : MAINTENANCE PRACTICES AND PRECAUTIONARY MEASURES","question":"State three ways of maintaining the specimens in (a) and (b)","images":[],"marking_scheme":"Ways of maintaining the specimens    -Sharpen the metal blades  -Wash and dry/clean after use  -Rub the metal blade with oil/grease to prevent rusting  -Keep the tools in a termite-free store to prevent the Wooden handles from damage  -Store in a cool, dry place after use  -Repair/replace damaged parts  -Straighten blades if bent","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2010>3>a","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"a","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"State one method of propagating each of specimens J (YAM TUBER), K (PLANTAIN), and L (TOMATO FRUIT) on the farm","images":[],"marking_scheme":"Method of propagating specimens J, K and Specimen J    Specimen J(Yam tuber ): By seeds setts/mini setts/ whole yam tuber  Specimen K (Plantain): By Suckers, Corms  Specimen J (Tomato Fruit): By seeds","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>3>b","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"b","group":"","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Describe briefly the method of planting each of specimens J, K, and L.","images":[],"marking_scheme":"Method of planting specimens J, K and L    Specimen J (Yam)    -Yam tubers are cut into setts  -Yam setts/seed yams are treated with an insecticide Or wood ash before planting/allow cut surface to dry under shade  -Make hole on the ridge/mound in the ground  -Place a yam sett or seed yam into the planting hole at a slanting angle with cut end up  -Yam setts/seed yams are planted at a spacing of 1m x 1m  -Cover the hole with soil  -Mulch with dry grass  -Provide stakes    Specimen K (Plantain)    -Dig holes about 60cm x 60cm x 60cm  -Fill the holes with a mixture of top soil and organic manure  -Place a sucker in each hole  -Cover the root part with soil  -The suckers are planted at a spacing of 4m x 4m  -Mulch planted suckers at the bases    Specimen L (Tomato)    -Sow seeds in nursery beds or boxes - under shade  Water regularly  -Transplant seedlings into the field after 4 -6 weeks or when the seedlings are at three-leaf stage  -Seedlings are planted at a spacing of 60cm x 60cm or 90cm x 40cm  -Transplant seedlings usually in the mornings or evenings  -Water seedlings daily  -Mulch seedlings  -Provide stakes","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>4>a","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"a","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Name specimens N, O and P.","images":[],"marking_scheme":"Names of Specimens N, O and P    N - Fish Scales  O - Feathers  P - Hoof","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2010>4>b","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"b","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"List two products that can be made from specimens M","images":[],"marking_scheme":"Products that can be made from specimen M (Milk);    -Cheese  -Skim milk  -Butter/butter fat  -lce cream  -Powdered milk  -Yoghurt   -Milk candy/milk sweet/butter scotch","marks":"1","difficulty":"1"},{"id":"theory>Agricultural Science Practical>2010>4>c","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"c","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"Make a drawing 8-10 cm long of a longitudinal section of specimens Q as observed with the aid of specimen S. Label the diagram fully.","images":["data:image/jpeg;base64,"],"marking_scheme":"","marks":"1","difficulty":"2"},{"id":"theory>Agricultural Science Practical>2010>4>d","subject":"Agricultural Science Practical","year":"2010","type":"Practical","sub_label":"d","group":"","topic":"ANIMAL PRODUCTION : TYPES AND CLASSIFICATION OF FARM ANIMALS","question":"\u0160tate two economic uses of each of specimens O and P.","images":[],"marking_scheme":"Economic uses of Specimens O and P and sr Specimen O (Feathers) ;    -Decorating room/hats  -Stuffing into pillows / mattresses  -Source of income  -Part of traditional regalia  -For fertilizers and mulch  -Used for making feather meal for livestock feeding  -For sporting goods, e.g shuttlecock used in badminton  -Artificial lures for fishing/bait     Specimen P (Hoof);    -For gum making/glue making  -For making room decoration  -Making buttons  -Source of income","marks":"1","difficulty":"1"}];